import React, { useRef, useState } from 'react';

interface FileUploadProps {
  onFileSelected: (file: File) => void;
  selectedFile: File | null;
  setSelectedFile: (file: File | null) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileSelected, selectedFile, setSelectedFile }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelected(e.target.files[0]);
    }
  };

  const handleBoxClick = () => {
    fileInputRef.current?.click();
  };

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(true);
  };
  const handleDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
  };
  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      onFileSelected(e.dataTransfer.files[0]);
    }
  };

  return (
    <>
      {!selectedFile && (
        <div
          className="custom-upload-box"
          tabIndex={0}
          onClick={handleBoxClick}
          onKeyDown={e => (e.key === 'Enter' || e.key === ' ') && handleBoxClick()}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
          aria-label="File upload area"
        >
          <input
            type="file"
            accept=".pdf,.doc,.docx,.txt,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document,application/msword,text/plain"
            className="file-input-hidden"
            ref={fileInputRef}
            onChange={handleFileChange}
            tabIndex={-1}
          />
          <span className="upload-icon">📤</span>
          <span className="upload-text">Drop your file here, or click to browse</span>
          <span className="upload-subtext">PDF, DOCX, or TXT</span>
        </div>
      )}
      {selectedFile && (
        <span className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-slate-100 dark:bg-neutral-700 border border-slate-300 dark:border-neutral-600 text-sm text-slate-700 dark:text-slate-300 font-medium">
          <span>📄</span>
          <span>{selectedFile.name}</span>
          <span className="text-slate-500 dark:text-slate-400">({(selectedFile.size / 1024).toFixed(1)} KB)</span>
          <button
            type="button"
            className="ml-2 text-slate-500 hover:text-accent dark:text-slate-400 dark:hover:text-accent focus-visible:text-accent transition-colors outline-none font-bold"
            aria-label="Remove file"
            onClick={() => setSelectedFile(null)}
          >
            ✕
          </button>
        </span>
      )}
    </>
  );
};

export default FileUpload;
